def filter_contains(subs):
    res = []
    for rec in hadith:
        text = rec.get('hadithTxt') or rec.get('Matn') or ''
        norm = normalize(text)
        ok = True
        for s in subs:
            if s not in norm:
                ok = False
                break
        if ok:
            res.append(text)
    return res

